questionvariables.text:
/* Inicialización de variables fuera del rango para entrar al ciclo */
L: 0;
N: 0;

/* Ciclo para asegurar 3 < L+N < 10 */
while (L+N <= 3 or L+N >= 10) do (
   L: 1 + rand(6),
   N: 1 + rand(6)
);

/* Respuesta correcta: (Alfabeto de 27 letras, Dígitos 0-9) */
ta1: (27^L) * (10^N);

/* Generación del ejemplo para el enunciado */
/* Generamos la parte de las letras */
L_str: "";
for i:1 thru L do L_str: sconcat(L_str, ascii(65 + rand(26)));

/* Generamos la parte de los números */
N_str: "";
for i:1 thru N do N_str: sconcat(N_str, string(rand(10)));

/* Concatenamos con un guion */
ejemplo: sconcat(L_str, "-", N_str);

/* Si L=1 o N=1, decir "letra" o "dígito" en singular */
letra: if L=1 then "letra" else "letras";
dig: if N=1 then "dígito" else "dígitos";
